/**
 * ResetList Component
 * Displays a list of resets with command details
 */

import React, { useState } from 'react';
import '../styles/ResetList.css';

export default function ResetList({ 
  resets, 
  selected, 
  onSelect, 
  onCreateNew,
  onDelete 
}) {
  const [filter, setFilter] = useState('');

  const filtered = resets.filter((reset, idx) => {
    const searchText = `${reset.command} ${reset.vnum || ''} ${reset.rawLine || ''}`.toLowerCase();
    return idx.toString().includes(filter) || searchText.includes(filter.toLowerCase());
  });

  const commandDescriptions = {
    M: 'Load mobile',
    O: 'Load object in room',
    G: 'Give object to mobile',
    E: 'Equip object on mobile',
    P: 'Put object in object',
    D: 'Set door state',
    R: 'Randomize exits',
  };

  return (
    <div className="reset-list">
      <div className="reset-list-header">
        <h3>Resets</h3>
        <button className="btn-primary" onClick={onCreateNew}>
          + New Reset
        </button>
      </div>

      <input
        type="text"
        placeholder="Filter resets..."
        value={filter}
        onChange={e => setFilter(e.target.value)}
        className="reset-filter"
      />

      <div className="reset-items">
        {filtered.length === 0 ? (
          <p className="empty-message">No resets found</p>
        ) : (
          filtered.map((reset, idx) => (
            <div
              key={idx}
              className={`reset-item ${selected === idx ? 'selected' : ''}`}
              onClick={() => onSelect(idx)}
            >
              <div className="reset-index">{idx}</div>
              <div className="reset-info">
                <div className="reset-command">
                  <span className="cmd-badge">{reset.command}</span>
                  <span className="cmd-desc">
                    {commandDescriptions[reset.command] || 'Unknown'}
                  </span>
                </div>
                {reset.vnum && (
                  <div className="reset-vnum">VNUM: {reset.vnum}</div>
                )}
                <div className="reset-raw">{reset.rawLine || ''}</div>
              </div>
              <button
                className="btn-delete"
                onClick={(e) => {
                  e.stopPropagation();
                  if (confirm(`Delete reset ${idx}?`)) {
                    onDelete(idx);
                  }
                }}
              >
                ✕
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
